from defusedxml import ElementTree as ET

def parse_xml_config(filename):
    tree = ET.parse(filename, parser=ET.XMLParser(external_entities=False))
    root = tree.getroot()

    settings = {}
    for element in root.iter():
        settings[element.tag] = element.text

    return settings